function n(r,t){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0,...t}).format(r)}function e(r){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",notation:"compact",maximumFractionDigits:1}).format(r)}function a(r){return new Intl.DateTimeFormat("en-US",{month:"short",day:"numeric",year:"numeric"}).format(new Date(r))}export{e as a,a as b,n as f};
